  INSERT INTO checklists (num, title, scope, sort_order) VALUES (1, 'Vor Aushub', 'project', 1) RETURNING id INTO v_cl;
  INSERT INTO checklist_sections (checklist_id, title, sort_order) VALUES (v_cl, NULL, 0) RETURNING id INTO v_sec;
  INSERT INTO checklist_items (section_id, text, sort_order) VALUES (v_sec, 'Eine Beweissicherung der Anliegerflächen, Bordsteine, Laternen, etc. wurde durchgeführt.', 0);
  INSERT INTO checklist_items (section_id, text, sort_order) VALUES (v_sec, 'Baugenehmigung liegt vor. (Roter Punkt)', 1);
  INSERT INTO checklist_items (section_id, text, sort_order) VALUES (v_sec, 'Die Kampfmittelfreiheit für das Baufeld ist gegeben.', 2);
  INSERT INTO checklist_items (section_id, text, sort_order) VALUES (v_sec, 'Eine Baugrunduntersuchung / Beprobung wurde durchgeführt — Geologisches Gutachten liegt vor.', 3);
  INSERT INTO checklist_items (section_id, text, sort_order) VALUES (v_sec, 'Sohle Baugrube und OK Planum wurden festgelegt. (Aushubplan vorhanden)', 4);
  INSERT INTO checklist_items (section_id, text, sort_order) VALUES (v_sec, 'Baugrube wurde vom Vermesser abgesteckt. Geofixpunkte für GPS-System angebracht (min. 3 Stück — Absprache mit Rohbauer) — Plan von Vermesser ablegen.', 5);
  INSERT INTO checklist_items (section_id, text, sort_order) VALUES (v_sec, 'Eine Lagerfläche für den Mutterboden wurde festgelegt.', 6);
  INSERT INTO checklist_items (section_id, text, sort_order) VALUES (v_sec, 'Eine Lagerfläche für den Baugrubenaushub wurde festgelegt — alles abfahren wo nicht benötigt wird!', 7);
  INSERT INTO checklist_items (section_id, text, sort_order) VALUES (v_sec, 'Die Baugrubensohle und Fundamente wurden vom Geologen abgenommen. Prüfbericht liegt vor.', 8);
  INSERT INTO checklist_items (section_id, text, sort_order) VALUES (v_sec, 'Die Baustelle wurde sauber für das Nachfolgegewerk hinterlassen. (Nachbegehung/Abnahme durchführen)', 9);
  INSERT INTO checklist_items (section_id, text, sort_order) VALUES (v_sec, 'Prüfstatik liegt vor.', 10);
  INSERT INTO checklists (num, title, scope, sort_order) VALUES (2, 'Aushub', 'project', 2) RETURNING id INTO v_cl;
  INSERT INTO checklist_sections (checklist_id, title, sort_order) VALUES (v_cl, NULL, 0) RETURNING id INTO v_sec;
  INSERT INTO checklist_items (section_id, text, sort_order) VALUES (v_sec, 'Vorleistungen (Wasser, Strom, etc.) wurden mit der ausführenden Firma abgestimmt.', 0);
  INSERT INTO checklist_items (section_id, text, sort_order) VALUES (v_sec, 'Bauvertrag wurde geprüft und mit Leistung abgeglichen — evtl. Nachträge vorab verhandelt und freigegeben.', 1);
  INSERT INTO checklist_items (section_id, text, sort_order) VALUES (v_sec, 'Genehmigung für Anker von Verbau von Nachbar liegt vor.', 2);
  INSERT INTO checklist_items (section_id, text, sort_order) VALUES (v_sec, 'Verbaustatik liegt vor.', 3);
  INSERT INTO checklist_items (section_id, text, sort_order) VALUES (v_sec, 'Alle Schnittstellen zu Nachgewerk (Tiefengründung am Verbaufuß, etc.) wurden vorab geklärt und kommuniziert. (Abstimmung Erdbau und Rohbau)', 4);
  INSERT INTO checklist_items (section_id, text, sort_order) VALUES (v_sec, 'Eine Absturzsicherung (Bauzaun) wurde angebracht und gegen Windeinwirkung gesichert.', 5);
  INSERT INTO checklist_items (section_id, text, sort_order) VALUES (v_sec, 'Der Verbau ist kraftschlüssig hinterfüllt — Nachweis von Verbaufirma vorhanden.', 6);
  INSERT INTO checklist_items (section_id, text, sort_order) VALUES (v_sec, 'Alle Bohrprotokolle und Ankerprotokolle liegen vor.', 7);
  INSERT INTO checklist_items (section_id, text, sort_order) VALUES (v_sec, 'Eine Lagerfläche für den Baugrubenaushub wurde festgelegt. Es ist zu klären, was für die Außenanlagen benötigt wird — alles abfahren wo nicht benötigt wird.', 8);
  INSERT INTO checklist_items (section_id, text, sort_order) VALUES (v_sec, 'Die Baugrubensohle wurde vom Geologen abgenommen (Fundamente auch).', 9);
  INSERT INTO checklist_items (section_id, text, sort_order) VALUES (v_sec, 'Es wurde eine Abnahme sowie eine Dokumentation durchgeführt (Böschungswinkel, Aushubkontur nach Aushubplan, Rampe, …).', 10);
  INSERT INTO checklists (num, title, scope, sort_order) VALUES (3, 'Rohbau', 'house', 3) RETURNING id INTO v_cl;
  INSERT INTO checklist_sections (checklist_id, title, sort_order) VALUES (v_cl, '1. Gründung', 0) RETURNING id INTO v_sec;
  INSERT INTO checklist_items (section_id, text, sort_order) VALUES (v_sec, 'Streifenfundament Gründungssohle (Abnahme Geologe). Größe Fundamente lt. Statik. (Bilder nummerieren und in PDF-Plan beschreiben)', 0);
  INSERT INTO checklist_items (section_id, text, sort_order) VALUES (v_sec, 'Unterbau fachgerecht eingebaut lt. Plan, Sauberkeitsschicht, Schottertragschicht.', 1);
  INSERT INTO checklist_items (section_id, text, sort_order) VALUES (v_sec, 'Erdung fachgerecht verlegt lt. Plan, Wanddurchführung für WU zugelassen. Erdungspunkte vorhanden.', 2);
  INSERT INTO checklist_items (section_id, text, sort_order) VALUES (v_sec, 'Erdung dokumentiert und geprüft. Dokumentation erhalten.', 3);
  INSERT INTO checklist_items (section_id, text, sort_order) VALUES (v_sec, 'Fugenblech oder Fugendichtband fachgerecht verlegt.', 4);
  INSERT INTO checklist_items (section_id, text, sort_order) VALUES (v_sec, 'Stärke der Bodenplatte geprüft.', 5);
  INSERT INTO checklist_items (section_id, text, sort_order) VALUES (v_sec, 'Vertikale Abdichtungsbänder vorhanden lt. Plan (bei weißer Wanne).', 6);
  INSERT INTO checklist_items (section_id, text, sort_order) VALUES (v_sec, 'Abdichtung der vertikalen und horizontalen Fugen von außen vorhanden.', 7);
  INSERT INTO checklist_items (section_id, text, sort_order) VALUES (v_sec, 'Fundamente unter Kragplatten im Arbeitsraum bis auf gewachsenen Boden gegründet.', 8);
  INSERT INTO checklist_items (section_id, text, sort_order) VALUES (v_sec, 'Horizontalsperre (Folie) unter Bodenplatte fachgerecht verlegt.', 9);
  INSERT INTO checklist_sections (checklist_id, title, sort_order) VALUES (v_cl, '2. Entwässerung', 1) RETURNING id INTO v_sec;
  INSERT INTO checklist_items (section_id, text, sort_order) VALUES (v_sec, 'Entwässerungssystem (Trenn- oder Mischsystem) laut Entwässerungsplan. Alle Abläufe im UG vorhanden und an der richtigen Stelle.', 0);
  INSERT INTO checklist_items (section_id, text, sort_order) VALUES (v_sec, 'Die Höhe des Kontrollschachts prüfen laut Plan — (Außenanlagen und Architekt vergleichen).', 1);
  INSERT INTO checklist_items (section_id, text, sort_order) VALUES (v_sec, 'Leitungen im richtigen Gefälle verlegt: Mindestgefälle 1%, keine 90°-Bögen (2× 45°), keine Unterbögen, Mindestdurchmesser DN 100.', 2);
  INSERT INTO checklist_items (section_id, text, sort_order) VALUES (v_sec, 'Dokumentation der verlegten Leitungen unter der Bodenplatte.', 3);
  INSERT INTO checklist_items (section_id, text, sort_order) VALUES (v_sec, 'RW, SW, Drainage an Kanal angeschlossen. Kanalbefahrung liegt vor. Druckprüfung von Schmutzwasserleitungen bis in Kanal liegt vor.', 4);
  INSERT INTO checklist_items (section_id, text, sort_order) VALUES (v_sec, 'Drainage fachgerecht verlegt — Gefälle ausreichend, Hochpunkt 20 cm unterhalb OK Betonsohle, Rohrscheitel unterhalb OK Betonsohle, Noppenbahn 3-lagig mit Gleitfolie zur Dämmung und Vlies zum Erdreich.', 5);
  INSERT INTO checklist_items (section_id, text, sort_order) VALUES (v_sec, 'Drainage gegen Rückstau gesichert und revisionsfähig. Drainagekontrollschächte an allen Richtungswechseln vorhanden.', 6);
  INSERT INTO checklist_items (section_id, text, sort_order) VALUES (v_sec, 'Für Entwässerung unter Bodenplatte Rohre durch Fundamente vorhanden lt. Plan.', 7);
  INSERT INTO checklist_items (section_id, text, sort_order) VALUES (v_sec, 'Drainagerohre in Filterschotter 8/16 verlegt. Um Filterschotter Geotextil verlegt.', 8);
  INSERT INTO checklist_items (section_id, text, sort_order) VALUES (v_sec, 'Hinterfüllung der Arbeitsräume fachgerecht verdichtet. Auffüllmaterial laut Vertrag. Verdichtungsnachweise vorhanden.', 9);
  INSERT INTO checklist_items (section_id, text, sort_order) VALUES (v_sec, 'GOK festgelegt (Höhe der Auffüllung vom Rohbauer) — laut Vertrag.', 10);
  INSERT INTO checklist_sections (checklist_id, title, sort_order) VALUES (v_cl, '3. Versorgungsleitungen', 2) RETURNING id INTO v_sec;
  INSERT INTO checklist_items (section_id, text, sort_order) VALUES (v_sec, 'Anträge in Absprache mit Fachplanern gestellt: Wasser, Strom, Medien (Glasfaser/Internet), Nah-/Fernwärme, Gas. Unterlagen/Anträge abgelegt.', 0);
  INSERT INTO checklist_items (section_id, text, sort_order) VALUES (v_sec, 'Einführungen passend zum Abdichtungssystem geprüft: Futterrohr bei Schwarzer Wanne, Kernbohrung oder KG-Rohr wo wieder ausgebaut wird.', 1);
  INSERT INTO checklist_items (section_id, text, sort_order) VALUES (v_sec, 'Hauseinführungen mit Versorgern und Tiefbaufirmen abgestimmt (Mehrsparte, Einzeleinführung, Abdichtung, Leerrohre, Lage, …).', 2);
  INSERT INTO checklist_items (section_id, text, sort_order) VALUES (v_sec, 'Versorgung zwischen den Häusern abgestimmt — Fachplaner, Rohbauer (Vertrag prüfen): Wasser, Strom, Medien, Nah-/Fernwärme, Gas.', 3);
  INSERT INTO checklist_items (section_id, text, sort_order) VALUES (v_sec, 'Werden weitere Leerrohre benötigt?', 4);
  INSERT INTO checklist_sections (checklist_id, title, sort_order) VALUES (v_cl, '4. Untergeschoss', 3) RETURNING id INTO v_sec;
  INSERT INTO checklist_items (section_id, text, sort_order) VALUES (v_sec, 'Bewehrung UG Bodenplatte lt. Statik (Abnahme Statiker).', 0);
  INSERT INTO checklist_items (section_id, text, sort_order) VALUES (v_sec, 'Bewehrung TG-Decke lt. Statik (Abnahme Statiker).', 1);
  INSERT INTO checklist_items (section_id, text, sort_order) VALUES (v_sec, 'Stahlbetonwände ordentlich geschalt. Fuge Wand-Decke verspachtelt. Sockelbereich für Sockelbeschichtung vorbereitet. Dreikantleisten lt. Vertrag eingebaut.', 2);
  INSERT INTO checklist_items (section_id, text, sort_order) VALUES (v_sec, 'Maße/Anzahl/Lage Bauteilöffnungen, Decken- und Wandaussparungen, Wandschlitze geprüft.', 3);
  INSERT INTO checklist_items (section_id, text, sort_order) VALUES (v_sec, 'Sperrpappe unter Mauerwerk vorhanden.', 4);
  INSERT INTO checklist_items (section_id, text, sort_order) VALUES (v_sec, 'Dickbeschichtung fachgerecht ausgeführt: 2K-KMB 2-lagig, 3 mm Schichtdicke trocken, Hohlkehle nach DIN 18533. Ausführungsprotokoll mit Bildern.', 5);
  INSERT INTO checklist_items (section_id, text, sort_order) VALUES (v_sec, 'Versorgungsleitungen durch UG-Wand abgedichtet.', 6);
  INSERT INTO checklist_items (section_id, text, sort_order) VALUES (v_sec, 'Dickbeschichtung unter Fuge Wand/Decke TG fachgerecht bis 30 cm unter Fuge. Ergänzung Dickbeschichtung über Schweißbahn + 10 cm.', 7);
  INSERT INTO checklist_items (section_id, text, sort_order) VALUES (v_sec, 'Lichtschächte fachgerecht montiert. Höhe lt. Plan (Außenanlagen und Architekt). Entwässerung lt. Plan und Detail.', 8);
  INSERT INTO checklist_sections (checklist_id, title, sort_order) VALUES (v_cl, '5. Außenmauerwerk', 4) RETURNING id INTO v_sec;
  INSERT INTO checklist_items (section_id, text, sort_order) VALUES (v_sec, 'Fugenbild, Fugenausbildung geprüft (keine Kreuzfugen, Fugen >0,5 mm verschlossen).', 0);
  INSERT INTO checklist_items (section_id, text, sort_order) VALUES (v_sec, 'Steinqualität (Rohdichte) laut Statik/Schallschutz (Bild von Steinbeschriftung).', 1);
  INSERT INTO checklist_items (section_id, text, sort_order) VALUES (v_sec, 'Deckenrandauflager unter Stahlbetondecke laut Vertrag eingebaut (Kantenschutz Cipolon).', 2);
  INSERT INTO checklist_items (section_id, text, sort_order) VALUES (v_sec, 'Meterriss vorhanden in jeder Wohnung und am Aufzug, Höhen geprüft (mit Laser).', 3);
  INSERT INTO checklist_items (section_id, text, sort_order) VALUES (v_sec, 'Maße Bauteilöffnungen/Aussparungen geprüft.', 4);
  INSERT INTO checklist_items (section_id, text, sort_order) VALUES (v_sec, 'Mauerwerk lot-, winkel- und waagerecht. Fugen >5 mm mit Mörtel verschlossen. Gleichmäßiger Kleber-/Mörtelauftrag.', 5);
  INSERT INTO checklist_items (section_id, text, sort_order) VALUES (v_sec, 'Brüstungshöhen geprüft.', 6);
  INSERT INTO checklist_items (section_id, text, sort_order) VALUES (v_sec, 'Tür- und Fensterhöhen und -breiten kontrolliert.', 7);
  INSERT INTO checklist_sections (checklist_id, title, sort_order) VALUES (v_cl, '6. Innenmauerwerk', 5) RETURNING id INTO v_sec;
  INSERT INTO checklist_items (section_id, text, sort_order) VALUES (v_sec, 'Verzahnung mit Edelstahlankern.', 0);
  INSERT INTO checklist_items (section_id, text, sort_order) VALUES (v_sec, 'Steinqualität (Rohdichte) laut Statik/Schallschutz (Bild von Steinbeschriftung).', 1);
  INSERT INTO checklist_items (section_id, text, sort_order) VALUES (v_sec, 'Fuge zur Stahlbetondecke geschlossen (bei nichttragenden Wänden, keine kraftschlüssige Verbindung).', 2);
  INSERT INTO checklist_items (section_id, text, sort_order) VALUES (v_sec, 'Keine Betonüberstände an Deckenuntersicht.', 3);
  INSERT INTO checklist_items (section_id, text, sort_order) VALUES (v_sec, 'Keine Versätze in den Stahlbetondecken (Untersicht der Halbfertigteile).', 4);
  INSERT INTO checklist_items (section_id, text, sort_order) VALUES (v_sec, 'Fugenbild, Fugenausbildung okay.', 5);
  INSERT INTO checklist_sections (checklist_id, title, sort_order) VALUES (v_cl, '7. Decken', 6) RETURNING id INTO v_sec;
  INSERT INTO checklist_items (section_id, text, sort_order) VALUES (v_sec, 'Bewehrung Decke über EG abgenommen (Abnahme Statiker).', 0);
  INSERT INTO checklist_items (section_id, text, sort_order) VALUES (v_sec, 'Bewehrung Decke über 1.OG abgenommen (Abnahme Statiker).', 1);
  INSERT INTO checklist_items (section_id, text, sort_order) VALUES (v_sec, 'Ringgurte, Stürze, Auflager lt. Statik vorhanden.', 2);
  INSERT INTO checklist_items (section_id, text, sort_order) VALUES (v_sec, 'Einbauteile Aufzug bestellen — Rohbauer bestellt direkt.', 3);
  INSERT INTO checklist_items (section_id, text, sort_order) VALUES (v_sec, 'Durchbrüche geprüft.', 4);
  INSERT INTO checklist_items (section_id, text, sort_order) VALUES (v_sec, 'Bodenschlitze geprüft.', 5);
  INSERT INTO checklist_sections (checklist_id, title, sort_order) VALUES (v_cl, '8. Betonfertigteiltreppen', 7) RETURNING id INTO v_sec;
  INSERT INTO checklist_items (section_id, text, sort_order) VALUES (v_sec, 'Steigung Treppe prüfen, ob mit Podest übereinstimmt.', 0);
  INSERT INTO checklist_items (section_id, text, sort_order) VALUES (v_sec, 'Treppe auf Elastomerlager (Schöck Tronsole) gelagert.', 1);
  INSERT INTO checklist_items (section_id, text, sort_order) VALUES (v_sec, 'Schallentkopplung prüfen (keine Verbindung zu Auflager, Wand, etc.). Treppe muss komplett frei gelagert sein.', 2);
  INSERT INTO checklist_items (section_id, text, sort_order) VALUES (v_sec, 'Untersicht und Übergang zum Podest. Maximaler Überstand Kante Treppe — Decke Podest 5 mm.', 3);
  INSERT INTO checklist_items (section_id, text, sort_order) VALUES (v_sec, 'Treppe sitzt parallel zur Wand (Wandabstand prüfen laut Plan). Breite von Treppenauge prüfen (laut Plan).', 4);
  INSERT INTO checklist_sections (checklist_id, title, sort_order) VALUES (v_cl, '9. Giebelmauerwerk bei Satteldach', 8) RETURNING id INTO v_sec;
  INSERT INTO checklist_items (section_id, text, sort_order) VALUES (v_sec, 'Ortstermin mit Zimmermann und Rohbauer vereinbaren und Höhen von Auflager prüfen.', 0);
  INSERT INTO checklist_items (section_id, text, sort_order) VALUES (v_sec, 'Dämmung auf Giebelwand prüfen.', 1);
  INSERT INTO checklist_items (section_id, text, sort_order) VALUES (v_sec, 'Nach Aufrichten sämtliche Wände hochgemauert (Brandschutz beachten). Auf Brandwand (Treppenhaus, Wohnungstrennwand) nichtbrennbare Dämmung verlegt.', 2);
  INSERT INTO checklist_items (section_id, text, sort_order) VALUES (v_sec, 'Stahlstützen untermörtelt.', 3);
  INSERT INTO checklist_items (section_id, text, sort_order) VALUES (v_sec, 'Ringgurte und Auflager betoniert (laut Statikplan).', 4);
  INSERT INTO checklists (num, title, scope, sort_order) VALUES (4, 'Abdichtungsarbeiten', 'house', 4) RETURNING id INTO v_cl;
  INSERT INTO checklist_sections (checklist_id, title, sort_order) VALUES (v_cl, '1. Abdichtung Dachflächen', 0) RETURNING id INTO v_sec;
  INSERT INTO checklist_items (section_id, text, sort_order) VALUES (v_sec, 'Abstimmung zwischen Abdichter, Zimmerer, Gipser und Flaschner ist erfolgt — Schnittstellen besprochen.', 0);
  INSERT INTO checklist_items (section_id, text, sort_order) VALUES (v_sec, 'Gefälleplanung liegt vor und entspricht den Vorgaben aus der Bauphysik. Dämmstärke und Wärmeleitgruppe passen mit Bauphysik überein und wurden dokumentiert.', 1);
  INSERT INTO checklist_items (section_id, text, sort_order) VALUES (v_sec, 'Überlappungen (8 cm) der Schweißbahnen gem. Herstellerangaben ausgeführt — stichprobenartig geprüft.', 2);
  INSERT INTO checklist_items (section_id, text, sort_order) VALUES (v_sec, 'Alle Anschlüsse an Abläufen/Notabläufen geprüft und sauber ausgeführt. Gefälle der Notabläufe geprüft.', 3);
  INSERT INTO checklist_items (section_id, text, sort_order) VALUES (v_sec, 'Fertiggestellte Oberflächen auf Beschädigung, Blasenbildung, unsaubere Ausführung geprüft.', 4);
  INSERT INTO checklist_items (section_id, text, sort_order) VALUES (v_sec, 'Alle Abläufe geprüft. Anstaubleche (bei Notabläufen) und Abdeckungen angebracht.', 5);
  INSERT INTO checklist_items (section_id, text, sort_order) VALUES (v_sec, 'Sicherung der Dachflächen (Sekuranten) abgestimmt. Nachweis und Bestätigung der Durchführung erhalten.', 6);
  INSERT INTO checklist_items (section_id, text, sort_order) VALUES (v_sec, 'Alle Bauteile (Lüftung, Dachausstieg, Sekuranten, etc.) mit Flüssigkunststoff bis +15 cm über FFB eingedichtet.', 7);
