  INSERT INTO checklist_items (section_id, text, sort_order) VALUES (v_sec, 'Belegung Kies/Begrünung abgestimmt. Belegung Dachflächen mit PV beachten. Kies ringsum und um alle Bauteile, –10 cm OK Blechattika, –15 cm zum Dachausstieg. Überdeckung mit Substrat geprüft.', 0);
