  INSERT INTO checklist_items (section_id, text, sort_order) VALUES (v_sec, 'Abläufe fachgerecht eingebaut, sauber und revisionierbar. Notabläufe sitzen über Ablauf und unter Schwelle Fenster/HST. (Bei einseitig offenem Balkon kein Notablauf nötig.)', 11);
