  INSERT INTO checklist_items (section_id, text, sort_order) VALUES (v_sec, 'Vorbegehung mit Gerüstbauer erfolgt. Abstimmung mit Rohbauer.', 0);
  INSERT INTO checklist_items (section_id, text, sort_order) VALUES (v_sec, 'Gerüst wird erst gestellt, wenn Rohbauer komplett aufgefüllt hat und EG fertig ist (Terrassen, Versorgungsleitungen, Lichtschächte, Lichthöfe, Erdplanum, TG fertig, …).', 1);
  INSERT INTO checklist_items (section_id, text, sort_order) VALUES (v_sec, 'Abstimmung Gerüst mit Fensterbauer, Gipser, Abdichter.', 2);
  INSERT INTO checklist_items (section_id, text, sort_order) VALUES (v_sec, 'Abstand zur Fassade abgestimmt. Konsolen notwendig?!', 3);
  INSERT INTO checklist_items (section_id, text, sort_order) VALUES (v_sec, 'Standsicherheit des Gerüstes gegeben und mit Schein bestätigt.', 4);
  INSERT INTO checklist_items (section_id, text, sort_order) VALUES (v_sec, 'Kamin, Balkone, Terrassen, Versorgungsleitungen, Brandschutzleiter berücksichtigt.', 5);
  INSERT INTO checklist_items (section_id, text, sort_order) VALUES (v_sec, 'Auf TG Füße möglichst weit nach oben drehen. Erste Lage Abdichtung vorab hergestellt.', 6);
  INSERT INTO checklist_items (section_id, text, sort_order) VALUES (v_sec, 'Dachterrassen, Balkone etc. erste Lage Abdichtung hergestellt.', 7);
  INSERT INTO checklist_items (section_id, text, sort_order) VALUES (v_sec, 'Treppentürme beachten — Lage festlegen.', 8);
  INSERT INTO checklist_items (section_id, text, sort_order) VALUES (v_sec, 'Bei Satteldach genügend Abstand zu Ortgang und Traufe — ggf. Abstimmung mit Zimmermann.', 9);
  INSERT INTO checklist_items (section_id, text, sort_order) VALUES (v_sec, 'Alle Arbeiten wo Gerüst benötigt wird sind erledigt: Fassade, Lüfter in der Fassade, Flachdach (Begrünung und Flaschner), Fenster, Balkongeländer, Kamin, Photovoltaik.', 10);
