INSERT INTO textbausteine (gewerk_id, label, body, sort_order) SELECT id, 'Putz nicht eben', 'Der Putz ist nicht eben aufgetragen — Wellenbildung sichtbar. Bitte abschleifen und neu beschichten.', 0 FROM gewerke WHERE name = 'Maler';
INSERT INTO textbausteine (gewerk_id, label, body, sort_order) SELECT id, 'Anstrich ungleichmäßig', 'Anstrich deckt nicht gleichmäßig — Schattierungen / Streifen sichtbar. Bitte zweiten Anstrich auftragen.', 1 FROM gewerke WHERE name = 'Maler';
INSERT INTO textbausteine (gewerk_id, label, body, sort_order) SELECT id, 'Farbspritzer', 'Farbspritzer auf Boden / Steckdose / Fenster. Bitte fachgerecht entfernen.', 2 FROM gewerke WHERE name = 'Maler';
INSERT INTO textbausteine (gewerk_id, label, body, sort_order) SELECT id, 'Übergang Decke', 'Übergang Wand zu Decke nicht sauber gezogen — Linie wellig. Nachbessern.', 3 FROM gewerke WHERE name = 'Maler';
INSERT INTO textbausteine (gewerk_id, label, body, sort_order) SELECT id, 'Fugenbild ungleichmäßig', 'Fugenbreite variiert deutlich. Fliesen aufnehmen und neu verlegen.', 4 FROM gewerke WHERE name = 'Fliesenleger';
INSERT INTO textbausteine (gewerk_id, label, body, sort_order) SELECT id, 'Silikonfuge unsauber', 'Silikonfuge weist Risse / Lücken auf. Bitte vollständig erneuern.', 5 FROM gewerke WHERE name = 'Fliesenleger';
INSERT INTO textbausteine (gewerk_id, label, body, sort_order) SELECT id, 'Fliese gebrochen', 'Fliese ist gebrochen / abgeplatzt. Austauschen.', 6 FROM gewerke WHERE name = 'Fliesenleger';
INSERT INTO textbausteine (gewerk_id, label, body, sort_order) SELECT id, 'Bodenablauf nicht bündig', 'Bodenablauf liegt nicht bündig zur Fliesenoberkante — Wasserstau möglich. Korrigieren.', 7 FROM gewerke WHERE name = 'Fliesenleger';
