INSERT INTO textbausteine (gewerk_id, label, body, sort_order) SELECT id, 'Lichtschalter ohne Funktion', 'Lichtschalter ohne Funktion. Verkabelung prüfen.', 10 FROM gewerke WHERE name = 'Elektro';
INSERT INTO textbausteine (gewerk_id, label, body, sort_order) SELECT id, 'Kabelende nicht eingeführt', 'Kabelende lose / nicht in Dose eingeführt. Fertig anschließen.', 11 FROM gewerke WHERE name = 'Elektro';
INSERT INTO textbausteine (gewerk_id, label, body, sort_order) SELECT id, 'Mischer tropft', 'Mischbatterie tropft. Dichtung erneuern.', 12 FROM gewerke WHERE name = 'Sanitär/Heizung';
INSERT INTO textbausteine (gewerk_id, label, body, sort_order) SELECT id, 'WC nicht fest', 'WC sitzt nicht fest am Boden. Befestigung nachziehen.', 13 FROM gewerke WHERE name = 'Sanitär/Heizung';
INSERT INTO textbausteine (gewerk_id, label, body, sort_order) SELECT id, 'Heizkörper kalt', 'Heizkörper wird oben kalt. Entlüften und Funktion prüfen.', 14 FROM gewerke WHERE name = 'Sanitär/Heizung';
INSERT INTO textbausteine (gewerk_id, label, body, sort_order) SELECT id, 'Ablauf riecht', 'Geruch aus Bodenablauf — Geruchsverschluss prüfen.', 15 FROM gewerke WHERE name = 'Sanitär/Heizung';
INSERT INTO textbausteine (gewerk_id, label, body, sort_order) SELECT id, 'Spachtelung sichtbar', 'Spachtelübergänge zwischen Platten klar sichtbar. Q3-Spachtelung erforderlich.', 16 FROM gewerke WHERE name = 'Trockenbau';
INSERT INTO textbausteine (gewerk_id, label, body, sort_order) SELECT id, 'Wand nicht lotrecht', 'Trockenbauwand nicht lotrecht. Korrigieren.', 17 FROM gewerke WHERE name = 'Trockenbau';
INSERT INTO textbausteine (gewerk_id, label, body, sort_order) SELECT id, 'Sockelleiste lose', 'Sockelleiste löst sich von der Wand. Neu befestigen.', 18 FROM gewerke WHERE name = 'Parkett';
INSERT INTO textbausteine (gewerk_id, label, body, sort_order) SELECT id, 'Dehnungsfuge fehlt', 'Keine Dehnungsfuge zur Wand erkennbar — bei Klima-Belastung Verformungsrisiko. Fuge anlegen.', 19 FROM gewerke WHERE name = 'Parkett';
INSERT INTO textbausteine (gewerk_id, label, body, sort_order) SELECT id, 'Kratzer in Oberfläche', 'Tiefer Kratzer in Parkettoberfläche — vermutlich durch Folgegewerk. Schleifen + neu versiegeln.', 20 FROM gewerke WHERE name = 'Parkett';
INSERT INTO textbausteine (gewerk_id, label, body, sort_order) SELECT id, 'Tür schleift', 'Tür schleift am Boden / Zarge. Höhe einstellen oder Türblatt kürzen.', 21 FROM gewerke WHERE name = 'Türen';
INSERT INTO textbausteine (gewerk_id, label, body, sort_order) SELECT id, 'Schließblech versetzt', 'Schließblech sitzt versetzt — Tür schließt nicht richtig. Justieren.', 22 FROM gewerke WHERE name = 'Türen';
INSERT INTO textbausteine (gewerk_id, label, body, sort_order) SELECT id, 'Dichtung lose', 'Türdichtung löst sich umlaufend. Erneuern.', 23 FROM gewerke WHERE name = 'Türen';
INSERT INTO textbausteine (gewerk_id, label, body, sort_order) SELECT id, 'Fugenanschluss undicht', 'Anschluss Fenster zu Mauerwerk nicht winddicht — Zugluft. Fugenband nacharbeiten.', 24 FROM gewerke WHERE name = 'Fenster';
INSERT INTO textbausteine (gewerk_id, label, body, sort_order) SELECT id, 'Fenster schließt nicht', 'Fensterflügel schließt nicht spaltfrei. Beschlag justieren.', 25 FROM gewerke WHERE name = 'Fenster';
INSERT INTO textbausteine (gewerk_id, label, body, sort_order) SELECT id, 'Beton nicht eben', 'Bodenplatte / Decke weist Unebenheiten > 5mm auf. Spachteln oder abschleifen.', 26 FROM gewerke WHERE name = 'Rohbau';
